#include<bits/stdc++.h>
using namespace std;

long long n,a[1000020],maxx,ant=1,lest,mid;

int main() {
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
	}
	sort(a+1,a+1+n);
    lest=a[1];
	for(int i=2;i<=n+1;i++){
		if(a[i]==lest){
			ant++;
		}else{
			if(ant%2==1){
				cout<<lest;
                return 0;
			}else{
				ant=1;
                lest=a[i];
			}
		}
	}
	return 0;
}
